    const stk = [];
    const result = s.split('');

    for (let i = 0; i < s.length; i++) {
        if (s[i] == '(') {
            stk.push(i);
        } else if (s[i] == ')') {
            if (stk.length > 0) {
                stk.pop();
            } else {
                result[i] = '';
            }
        }
