import java.util.Stack;

public String minRemoveToMakeValid(String s) {
    Stack<Integer> stk = new Stack<>();
    char[] result = s.toCharArray();

    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '(') {
            stk.push(i);
        } else if (s.charAt(i) == ')') {
            if (!stk.empty()) {
                stk.pop();
            } else {
                result[i] = '-';
            }
        }
    }

    while (!stk.empty()) {
        result[stk.pop()] = '-';
    }

    return new String(result).replace("-", "");
}
```


